import { useEffect, useState } from "react";
import { api, getAuthToken } from "../api";

export default function Orders() {
  const [orders, setOrders] = useState([]);
  const [error, setError] = useState("");

  useEffect(() => {
    const fetchOrders = async () => {
      if (!getAuthToken()) {
        setError("Please login to view orders.");
        return;
      }

      try {
        const res = await api.get("/orders/");
        setOrders(res.data);
      } catch (err) {
        setError("Unable to fetch orders.");
      }
    };

    fetchOrders();
  }, []);

  return (
    <div className="page">
      <div className="page-header">
        <h1>📦 Order History</h1>
        <p>Track and manage your purchases</p>
      </div>

      {error && <div className="error-message">{error}</div>}

      {orders.length === 0 ? (
        <div className="empty-state">
          <div className="empty-icon">📦</div>
          <h3>No orders yet</h3>
          <p>Start shopping to place your first order</p>
        </div>
      ) : (
        <div className="orders-container">
          {orders.map((order) => (
            <div className="order-card" key={order.id}>
              <div className="order-header">
                <div>
                  <div className="order-id">Order #{order.id}</div>
                  <div className="order-date">{new Date(order.created_at).toLocaleDateString()}</div>
                </div>
                <div className="order-status">✓ Completed</div>
              </div>
              
              <div className="order-items">
                <h4>Items:</h4>
                <ul>
                  {order.items_detail.map((item) => (
                    <li key={item.id}>
                      <span>{item.medicine_detail.name}</span>
                      <span className="qty">× {item.quantity}</span>
                      <span className="price">₹ {(item.quantity * item.medicine_detail.price).toFixed(2)}</span>
                    </li>
                  ))}
                </ul>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
